import React, { useMemo } from "react";
import { useUploader } from "../MainUploader";
import {Box, Button, Flex, Image, Text} from "../../../../";

const SingleImageUploader = () => {
    const { onPick, files, removeFile, disabled, isClassicUploader } = useUploader();

    const current = useMemo(() => (files.length ? files[0] : null), [files]);
    const uri =
        current && typeof current.file === "object" && "uri" in current.file
            ? current.file.uri
            : null;

    if (isClassicUploader) {
        return (
            <Flex w={"full"} gap={2} flexDirection={"row"} alignItems={"center"}>
                <Button label={"Choose image"}
                        w={'85%'} onClick={onPick as any} disabled={disabled} />
                <Button
                    icon="pi pi-times"
                    size={'md'}
                    w={20}
                    severity={"danger"}
                    onClick={removeFile(0)}
                    disabled={!current || disabled}
                />
                {!!current?.name && <Text as={"span"}>{current.name}</Text>}
            </Flex>
        );
    }

    return (
        <Box w={"full"} gap={2}>
            <Flex w={'full'} gap={5} flexDirection={"row"}>
                <Button label={uri ? "Change image" : "Choose image"}
                        w={'85%'} onClick={onPick as any} disabled={disabled} flex={75} />
                <Button
                    icon="pi pi-times"
                    size={'md'}
                    w={20}
                    severity={"danger"}
                    onClick={removeFile(0)}
                    disabled={disabled}
                    flex={1}
                />
            </Flex>
            {uri ? (
                <Flex position={"relative"} w={"full"}>
                    <Image w={'full'} aspectRatio={1} objectFit={'contain'} src={uri} alt={"Preview"} />
                </Flex>
            ) : (
                <Text as={"span"}>Tap to pick an image</Text>
            )}
        </Box>
    );
};

export default SingleImageUploader;
